import{_ as t,c as a,o as r,ae as c}from"./chunks/framework.B7Y1jjX-.js";const p=JSON.parse('{"title":"响应式Effect的生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/库/React/4Escape Hatches/5响应式Effect的生命周期.md","filePath":"generated-notes/前端/库/React/4Escape Hatches/5响应式Effect的生命周期.md"}'),n={name:"generated-notes/前端/库/React/4Escape Hatches/5响应式Effect的生命周期.md"};function f(o,e,s,l,h,i){return r(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="响应式effect的生命周期" tabindex="-1">响应式Effect的生命周期 <a class="header-anchor" href="#响应式effect的生命周期" aria-label="Permalink to &quot;响应式Effect的生命周期&quot;">​</a></h1><p>这部分有点难，我应该再看一遍</p><h2 id="effect-的生命周期" tabindex="-1">Effect 的生命周期 <a href="https://zh-hans.react.dev/learn/lifecycle-of-reactive-effects#the-lifecycle-of-an-effect" title="Link for Effect 的生命周期" target="_blank" rel="noreferrer"></a> <a class="header-anchor" href="#effect-的生命周期" aria-label="Permalink to &quot;Effect 的生命周期 [](https://zh-hans.react.dev/learn/lifecycle-of-reactive-effects#the-lifecycle-of-an-effect &quot;Link for Effect 的生命周期&quot;)&quot;">​</a></h2><p>每个 React 组件都经历相同的生命周期：</p><ul><li>当组件被添加到屏幕上时，它会进行组件的 <strong>挂载</strong>。</li><li>当组件接收到新的 props 或 state 时，通常是作为对交互的响应，它会进行组件的 <strong>更新</strong>。</li><li>当组件从屏幕上移除时，它会进行组件的 <strong>卸载</strong>。</li></ul><p><strong>代码中的每个 Effect 应该代表一个独立的同步过程。</strong></p><p>在上面的示例中，删除一个 Effect 不会影响另一个 Effect 的逻辑。这表明它们同步不同的内容，因此将它们拆分开是有意义的。另一方面，如果将一个内聚的逻辑拆分成多个独立的 Effects，代码可能会看起来更加“清晰”，但 <a href="https://zh-hans.react.dev/learn/you-might-not-need-an-effect#chains-of-computations" target="_blank" rel="noreferrer">维护起来会更加困难</a>。这就是为什么你应该考虑这些过程是相同还是独立的，而不是只考虑代码是否看起来更整洁。</p><h4 id="全局变量或可变值可以作为依赖项吗" tabindex="-1">全局变量或可变值可以作为依赖项吗？ <a href="https://zh-hans.react.dev/learn/lifecycle-of-reactive-effects#can-global-or-mutable-values-be-dependencies" title="Link for 全局变量或可变值可以作为依赖项吗？" target="_blank" rel="noreferrer"></a> <a class="header-anchor" href="#全局变量或可变值可以作为依赖项吗" aria-label="Permalink to &quot;全局变量或可变值可以作为依赖项吗？ [](https://zh-hans.react.dev/learn/lifecycle-of-reactive-effects#can-global-or-mutable-values-be-dependencies &quot;Link for 全局变量或可变值可以作为依赖项吗？&quot;)&quot;">​</a></h4><p>可变值（包括全局变量）不是响应式的。</p><p>例如，像 <a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Location/pathname" target="_blank" rel="noreferrer"><code>location.pathname</code></a> 这样的可变值不能作为依赖项。它是可变的，因此可以在 React 渲染数据流之外的任何时间发生变化。更改它不会触发组件的重新渲染。因此，即使在依赖项中指定了它，React 也无法知道在其更改时重新同步 Effect。这也违反了 React 的规则，因为在渲染过程中读取可变数据（即在计算依赖项时）会破坏 <a href="https://zh-hans.react.dev/learn/keeping-components-pure" target="_blank" rel="noreferrer">纯粹的渲染</a>。相反，应该使用 <a href="https://zh-hans.react.dev/learn/you-might-not-need-an-effect#subscribing-to-an-external-store" target="_blank" rel="noreferrer"><code>useSyncExternalStore</code></a> 来读取和订阅外部可变值。</p><p><strong>另外，像 <a href="https://zh-hans.react.dev/reference/react/useRef#reference" target="_blank" rel="noreferrer"><code>ref.current</code></a> 或从中读取的值也不能作为依赖项。<code>useRef</code> 返回的 ref 对象本身可以作为依赖项</strong>，但其 <code>current</code> 属性是有意可变的。它允许 <a href="https://zh-hans.react.dev/learn/referencing-values-with-refs" target="_blank" rel="noreferrer">跟踪某些值而不触发重新渲染</a>。但由于更改它不会触发重新渲染，它不是响应式值，React 不会知道在其更改时重新运行 Effect。</p>',11)])])}const _=t(n,[["render",f]]);export{p as __pageData,_ as default};
